const data = $input.first().json;
const awards = data.results || [];

const results = [];
for (const award of awards) {
  const naicsCode = (award.naics_code || '').toString();
  const awardAmount = award['Award Amount'] || 0;
  const postedDate = award['Base Obligation Date'] || new Date().toISOString().split('T')[0];
  const internalId = award.generated_internal_id || Math.random().toString(36).slice(2);

  let score = 50;
  if (naicsCode === '561700' || naicsCode.startsWith('5617')) score += 30;
  if (awardAmount >= 500000) score += 20;
  else if (awardAmount >= 100000) score += 10;
  score += 10;
  const daysOld = Math.floor((Date.now() - new Date(postedDate).getTime()) / 86400000);
  if (daysOld <= 7) score += 15;
  else if (daysOld <= 30) score += 5;
  score = Math.min(100, score);

  if (score >= 50) {
    results.push({
      json: {
        opportunity_id: `usaspending-${internalId}`,
        title: (award['Description'] || 'Federal Contract Award').substring(0, 200),
        description: (award['Description'] || '').substring(0, 1000),
        source: 'usaspending',
        event_date: postedDate,
        total_obligated_amount: typeof awardAmount === 'number' ? awardAmount : parseFloat(awardAmount) || 0,
        url: `https://usaspending.gov/award/${internalId}`,
        naics_codes: naicsCode,
        place_of_performance: '',
        set_asides: '',
        url_hash: `usa-${internalId}`,
        source_data: JSON.stringify(award).substring(0, 500),
        award_score: score
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _empty: true, total: 0, message: 'No awards found above threshold', award_score: 0 } }];
}

return results;

const items = $input.all();
const total = items.length;
const highScore = items.filter(i => (i.json.award_score || 0) >= 80).length;
const avgScore = total > 0 ? Math.round(items.reduce((s, i) => s + (i.json.award_score || 0), 0) / total) : 0;

const topAwards = items
  .sort((a, b) => (b.json.award_score || 0) - (a.json.award_score || 0))
  .slice(0, 5)
  .map(i => `• [${i.json.award_score}pts] ${(i.json.title || 'Unknown').substring(0, 80)} — $${((i.json.total_obligated_amount || 0)/1000).toFixed(0)}K`)
  .join('\n');

const today = new Date().toLocaleDateString('en-US', {weekday:'long', month:'short', day:'numeric'});

return [{
  json: {
    text: `*Phase 5 Contract Intelligence — ${today}*\n\n📊 *${total}* NAICS 5617xx contracts found | 🎯 *${highScore}* score ≥80 | avg score *${avgScore}*\n\n*Top Awards:*\n${topAwards || 'None found'}\n\n_USASpending.gov • NAICS 561700-561790_`
  }
}];
